void sparse_matvec(int n, const int *rowptr, const int *colidx, const double *values, const double *x, double *y) {
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; i++) {
        double sum = 0.0;
        int start = rowptr[i];
        int end = rowptr[i + 1];
        int j = start;
        // 4路循环展开
        for (; j <= end - 4; j += 4) {
            sum += values[j] * x[colidx[j]]
                 + values[j+1] * x[colidx[j+1]]
                 + values[j+2] * x[colidx[j+2]]
                 + values[j+3] * x[colidx[j+3]];
        }
        for (; j < end; j++) {
            sum += values[j] * x[colidx[j]];
        }
        y[i] = sum;
    }
}

double dot_product(const double *x, const double *y, int n) {
    double sum = 0.0;
    #pragma omp parallel for reduction(+:sum) simd
    for (int i = 0; i < n; i++) {
        sum += x[i] * y[i];
    }
    return sum;
}

void sparse_matvec(int n, const int *rowptr, const int *colidx, const double *values, const double *x, double *y) {
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; i++) {
        double sum = 0.0;
        int start = rowptr[i];
        int end = rowptr[i + 1];
        for (int j = start; j < end; j++) {
            // 预取后续的 colidx 和 x 元素
            #if defined(__GNUC__) || defined(__clang__)
            __builtin_prefetch(&colidx[j + 8], 0, 3);
            __builtin_prefetch(&x[colidx[j + 4]], 0, 0);
            #endif
            sum += values[j] * x[colidx[j]];
        }
        y[i] = sum;
    }
}

将 `k` 循环与 `j` 循环调换位置，使最内层循环变为对 `j` 的连续访问。同时，将 `C[i][j] *= beta` 的初始化与累加计算合并或分离优化，以提高向量化效率。

优化后的核心代码：
```cpp
#pragma omp parallel for private(j, k)
for (int i = 0; i < _PB_N; i++) {
  for (int j = 0; j <= i; j++) {
    C[i][j] *= beta;
  }
  for (int k = 0; k < _PB_M; k++) {
    DATA_TYPE temp = alpha * A[i][k];
    #pragma omp simd
    for (int j = 0; j <= i; j++) {
      C[i][j] += temp * A[j][k];
    }
  }
}
```

对 `i`, `j`, `k` 维度进行分块（Tiling），将数据缓存在 L1/L2 Cache 中，最大化时间局部性。结合 OpenMP 多线程并行化。

```cpp
int BLOCK_I = 64;
int BLOCK_J = 64;
int BLOCK_K = 64;
#pragma omp parallel for collapse(2) private(i, j, k)
for (int ii = 0; ii < _PB_N; ii += BLOCK_I) {
  for (int jj = 0; jj < _PB_N; jj += BLOCK_J) {
    // 结合分块进行局部乘加更新...
  }
}
```

1. 调整循环顺序，将 k 循环移至最外层或进行分块（Tiling），以提高 A 和 B 的空间局部性。
2. 引入寄存器变量暂存 alpha * B[i][k] 和 alpha * A[i][k]，避免在内层循环中重复计算和访存。
3. 对 C[i][j] 的初始化（C[i][j] *= beta）与累加计算解耦，或合并以减少写回带宽。

优化后的 CPU 核心循环结构示例：
```cpp
// 1. 独立初始化 C
#pragma omp parallel for private(j)
for (i = 0; i < _PB_N; i++) {
  for (j = 0; j <= i; j++) {
    C[i][j] *= beta;
  }
}

// 2. 分块与循环重组 (以提高 L1/L2 Cache 命中率)
#pragma omp parallel for private(k, j, tmp_A, tmp_B)
for (i = 0; i < _PB_N; i++) {
  for (k = 0; k < _PB_M; k++) {
    DATA_TYPE tmp_A = alpha * A[i][k];
    DATA_TYPE tmp_B = alpha * B[i][k];
    for (j = 0; j <= i; j++) {
      C[i][j] += A[j][k] * tmp_B + B[j][k] * tmp_A;
    }
  }
}
```

通过交换循环顺序（Loop Permutation），将对 `j` 的循环移到最内层，使得 `B[i][j]` 和 `B[k][j]` 的内存访问在空间上连续（Row-major 友好）。同时，引入分块（Tiling）以提高 L1/L2 缓存命中率，并利用 SIMD 向量化。

优化后的核心计算逻辑如下：
```cpp
// 循环重组：i -> k -> j
for (int i = 0; i < _PB_M; i++) {
  for (int j = 0; j < _PB_N; j++) {
    B[i][j] = alpha * B[i][j]; // 先应用 alpha 缩放（或在最后统一缩放）
  }
}
// 重新组织累加过程以实现连续访问
for (int i = 0; i < _PB_M; i++) {
  for (int k = i + 1; k < _PB_M; k++) {
    DATA_TYPE tmp = A[k][i];
    #pragma omp simd
    for (int j = 0; j < _PB_N; j++) {
      B[i][j] += tmp * B[k][j];
    }
  }
}
```

